import React, { createContext, useContext, useEffect, useState } from "react"

// 1️⃣ Supported currencies
const SUPPORTED_CURRENCIES = {
  NGN: { symbol: "₦", locale: "en-NG" },
  USD: { symbol: "$", locale: "en-US" },
  EUR: { symbol: "€", locale: "de-DE" },
  INR: { symbol: "₹", locale: "en-IN" },
}

// 2️⃣ Context
const CurrencyContext = createContext(null)

// 3️⃣ Provider
export const CurrencyProvider = ({ children }) => {
  const baseCurrency = "NGN"
  const [displayCurrency, setDisplayCurrency] = useState("NGN")

  const [exchangeRates, setExchangeRates] = useState({
    NGN: 1,
    USD: 0.00067,
    EUR: 0.00062,
    INR: 0.055,
  })

  // Detect locale
  useEffect(() => {
    const locale = navigator.language || ""

    if (locale.includes("NG")) setDisplayCurrency("NGN")
    else if (locale.includes("IN")) setDisplayCurrency("INR")
    else if (locale.includes("DE")) setDisplayCurrency("EUR")
    else setDisplayCurrency("USD")
  }, [])

  const convertAmount = (amountInBase = 0) => {
    const rate = exchangeRates[displayCurrency] || 1
    return amountInBase * rate
  }

  const formatAmount = (amountInBase = 0) => {
    const converted = convertAmount(amountInBase)
    const { locale } = SUPPORTED_CURRENCIES[displayCurrency]

    return new Intl.NumberFormat(locale, {
      style: "currency",
      currency: displayCurrency,
    }).format(converted)
  }

  return (
    <CurrencyContext.Provider
      value={{
        baseCurrency,
        displayCurrency,
        setDisplayCurrency,
        exchangeRates,
        setExchangeRates,
        convertAmount,
        formatAmount,
        supportedCurrencies: SUPPORTED_CURRENCIES,
      }}
    >
      {children}
    </CurrencyContext.Provider>
  )
}

// 4️⃣ Hook (STRICT)
export const useCurrency = () => {
  const context = useContext(CurrencyContext)
  if (!context) {
    throw new Error("useCurrency must be used inside CurrencyProvider")
  }
  return context
}
